struct LeakedData { 
    data_object: String,
    metadata: Option<u32>,
}

fn check_for_leak(item: &LeakedData) -> Option<String> {
    match item.data_object.len() >= 15 { 
        true => match item.metadata { 
            Some(id) if id % 2 == 0 => Some(format!("High risk leak from user {}", id)), 
            Some(_) => None,
            None => Some(String::from("Unclassified potential leak"))
        },
        false => None
    }
}

fn main() {
    let item1 = LeakedData { data_object: String::from("superlongsecretkey"), metadata: Some(2) };
    let item2 = LeakedData { data_object: String::from("shortkey"), metadata: Some(4) };
    let item3 = LeakedData { data_object: String::from("anotherverylongkeythatisatleastfifteenchars"), metadata: None };

    println!("Check 1 Result: {:?}", check_for_leak(&item1));
    println!("Check 2 Result: {:?}", check_for_leak(&item2));
    println!("Check 3 Result: {:?}", check_for_leak(&item3));
}

use std::collections::VecDeque;

struct Point {
    x: f64,
    y: f64,
}

struct BoundaryQuery {
    p1: Point,
    p2: Point,
}

fn is_on_segment(p: &Point, a: &Point, b: &Point) -> bool {
    if (a.x <= p.x && p.x <= b.x || b.x <= p.x && p.x <= a.x)
        && (a.y <= p.y && p.y <= b.y || b.y <= p.y && p.y <= a.y)
    {
        let cross_product = (p.y - a.y) * (b.x - a.x) - (p.x - a.x) * (b.y - a.y);
        cross_product.abs() < 1e-9
    }
    else {
        false
    }
}

fn check_boundary(query: &BoundaryQuery, p: &Point) -> bool {
    match (p.x > query.p1.x, p.x > query.p2.x, p.y > query.p1.y, p.y > query.p2.y) {
        (true, true, true, true) => true,
        (false, false, false, false) => true,
        (guard_x_min, guard_x_max, guard_y_min, guard_y_max) if !(guard_x_min && guard_x_max && guard_y_min && guard_y_max) => {
            is_on_segment(p, &query.p1, &query.p2)
        }
        _ => false
    }
}

fn main() {
    let query = BoundaryQuery { p1: Point { x: 0.0, y: 0.0 }, p2: Point { x: 10.0, y: 10.0 } };
    let point_inside = Point { x: 5.0, y: 5.0 };
    let point_on_edge = Point { x: 7.0, y: 7.0 };

    println!("Point (5, 5) is within bounds: {}", check_boundary(&query, &point_inside));

    println!("Point (7, 7) is within bounds: {}", check_boundary(&query, &point_on_edge));
}

use std::io;

struct TimerState {
    is_running: bool,
    elapsed_seconds: i32,
}

impl TimerState {
    fn new() -> Self {
        TimerState {
            is_running: false,
            elapsed_seconds: 0,
        }
    }

    fn process_tick(&self, delta: i32) -> String {
        match (self.elapsed_seconds % 5, self.elapsed_seconds / 10) {
            (0, 0) if delta > 0 => "Perfect start state.".to_string(),
            (r, d) if r == 4 && d >= 2 => format!("Almost done, cycle {} is nearing its end.", d),
            (_, _) if self.elapsed_seconds < -10 => "Error: Time went backward significantly.".to_string(),
            (_, _) => "Normal tick processed.".to_string(),
        }
    }
}

fn main() {
    let state = TimerState::new();
    println!("Initial State Check: {}", state.process_tick(1));

    let state2 = TimerState { elapsed_seconds: 4, is_running: true };
    println!("Mid Cycle Check: {}", state2.process_tick(1));

    let state3 = TimerState { elapsed_seconds: -15, is_running: false };
    println!("Error State Check: {}", state3.process_tick(1));
}

use std::collections::HashMap;

struct GameConfig {
    settings: HashMap<String, String>,
}

impl GameConfig {
    fn new() -> Self {
        GameConfig { settings: HashMap::new() }
    }

    fn set_setting(&mut self, key: &str, value: &str) {
        self.settings.insert(key.to_string(), value.to_string());
    }

    fn get_active_priority(&self, setting_name: &str) -> Option<String> {
        match self.settings.get(setting_name) {
            Some(value) => {
                if value.contains("true") && self.settings.contains_key("is_core") && self.settings["is_core"].contains("enabled") {
                    Some(format!("Priority: {}", value))
                } else if value.contains("fallback") {
                    Some(format!("Fallback Applied: {}", value))
                } else { 
                    None 
                }
            }
            None => None
        }
    }
}

fn main() {
    let mut config = GameConfig::new();
    config.set_setting("player_hp", "100");
    config.set_setting("is_core", "enabled_for_mod_xyz");
    config.set_setting("ui_display", "true_with_fallback_data");

    if let Some(message) = config.get_active_priority("ui_display") {
        println!("Successfully parsed setting: {}", message);
    }

    config.set_setting("player_hp", "50");
    if let Some(message) = config.get_active_priority("player_hp") {
        println!("Successfully parsed setting: {}", message);
    } else {
        println!("Setting player_hp used default logic.");
    }
}

use std::collections::HashMap;

struct DataPacket {
    id: u32,
    value_str: String,
}

fn process_packet(packet: DataPacket) -> Option<i32> {
    if packet.id % 2 == 0 && packet.value_str.starts_with("A") {
        Some(10 * (packet.id as i32)) 
    } else if packet.id % 3 == 0 && packet.value_str.contains("Error") {
        None
    } else if packet.id > 100 {
        Some(-1)
    } else {
        None
    }
}

fn main() {
    let packets = vec![
        DataPacket { id: 2, value_str: "Apple".to_string() },
        DataPacket { id: 3, value_str: "CriticalError".to_string() },
        DataPacket { id: 101, value_str: "Test".to_string() },
        DataPacket { id: 4, value_str: "Banana".to_string() } 
    ];

    for packet in packets {
        match process_packet(packet) {
            Some(result) => println!("Successfully processed ID {} with result {}", 2, result),
            None => println!("Skipped or failed processing for some conditions.")
        }
    }
}
